mapper.select:
SELECT p.id, p.user_id, p.title, p.content, p.view_count, p.like_count, p.comment_count, p.create_time, u.nickname AS user_nickname, u.avatar AS user_avatar FROM post p LEFT JOIN user u ON p.user_id = u.id WHERE p.status = 1
AND p.user_id = #{userId}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.is_top DESC, p.create_time DESC LIMIT #{offset}, #{pageSize}
